const items = $input.all();
const files = items.map(function(it, i){
  const fn = (it.binary && it.binary.data && it.binary.data.fileName) ? it.binary.data.fileName : ("paper-" + (i+1) + ".pdf");
  return { name: fn, is_ocr: false, data_id: ("paper-" + i) };
});
return [{ json: { requestBody: { enable_formula: true, enable_table: true, language: "en", model_version: "vlm", files: files } } }];

const resp = $("MinerU Submit Batch").first().json;
const urls = (resp.data && resp.data.file_urls) || [];
const batchId = resp.data && resp.data.batch_id;
const pdfs = $("Read PDFs").all();
return pdfs.map(function(it, i){
  const bin = it.binary || {};
  const fn = (bin.data && bin.data.fileName) ? bin.data.fileName : ("paper-" + (i+1) + ".pdf");
  const newBin = {};
  if (bin.data) { newBin.data = Object.assign({}, bin.data, { mimeType: "", fileName: fn }); }
  return { json: { uploadUrl: urls[i], batchId: batchId, name: fn }, binary: newBin };
});

const NL = String.fromCharCode(10);
const items = $input.all();
const parts = [];
for (let i = 0; i < items.length; i++) {
  const bin = items[i].binary || {};
  const key = Object.keys(bin)[0];
  let txt = "";
  if (key) {
    try { txt = (await this.helpers.getBinaryDataBuffer(i, key)).toString("utf8"); }
    catch (e) { txt = Buffer.from(bin[key].data || "", "base64").toString("utf8"); }
  }
  const name = (bin[key] && bin[key].fileName) || ("paper-" + i);
  parts.push({ name: name, txt: txt });
}
parts.sort(function(a, b){ return a.name.localeCompare(b.name); });
const sep = NL + NL + "---" + NL + NL;
const header = "# 文献精读报告" + NL + NL + "生成时间：" + $now.toISO() + NL + NL + "共 " + parts.length + " 篇文献" + sep;
const reportMarkdown = header + parts.map(function(p){ return p.txt; }).join(sep);

function esc(s){ return s.split("&").join("&amp;").split("<").join("&lt;").split(">").join("&gt;"); }
function boldify(s){ const a = s.split("**"); let r = ""; for (let i = 0; i < a.length; i++){ r += (i % 2 === 1) ? ("<strong>" + a[i] + "</strong>") : a[i]; } return r; }
const lines = reportMarkdown.split(NL);
const htmlParts = []; let inList = false;
function closeList(){ if (inList) { htmlParts.push("</ul>"); inList = false; } }
for (let i = 0; i < lines.length; i++) {
  const ln = lines[i];
  const t = ln.trim();
  if (t.length === 0) { closeList(); continue; }
  if (ln.charAt(0) === "<") { closeList(); htmlParts.push(ln); continue; }
  if (t === "---") { closeList(); htmlParts.push("<hr>"); continue; }
  if (ln.indexOf("### ") === 0) { closeList(); htmlParts.push("<h3>" + boldify(esc(ln.slice(4))) + "</h3>"); continue; }
  if (ln.indexOf("## ") === 0) { closeList(); htmlParts.push("<h2>" + boldify(esc(ln.slice(3))) + "</h2>"); continue; }
  if (ln.indexOf("# ") === 0) { closeList(); htmlParts.push("<h1>" + boldify(esc(ln.slice(2))) + "</h1>"); continue; }
  if (ln.indexOf("- ") === 0 || ln.indexOf("* ") === 0) { if (!inList) { htmlParts.push("<ul>"); inList = true; } htmlParts.push("<li>" + boldify(esc(ln.slice(2))) + "</li>"); continue; }
  closeList(); htmlParts.push("<p>" + boldify(esc(ln)) + "</p>");
}
closeList();
const style = "<style>body{font-family:-apple-system,'Segoe UI','Microsoft YaHei',sans-serif;max-width:900px;margin:24px auto;padding:0 16px;line-height:1.7;color:#222}img{max-width:100%;height:auto;display:block;margin:10px 0}h1{font-size:24px}h2{font-size:20px;border-bottom:1px solid #eee;padding-bottom:4px}h3{font-size:16px;color:#0a58ca}hr{border:none;border-top:1px solid #ddd;margin:28px 0}</style>";
const htmlReport = '<!doctype html><html><head><meta charset="utf-8">' + style + '</head><body>' + htmlParts.join(NL) + '</body></html>';
return [{ json: { reportMarkdown: reportMarkdown, htmlReport: htmlReport, paperCount: parts.length } }];

const items = $input.all();
const out = [];
for (let i = 0; i < items.length; i++) {
  const bin = items[i].binary || {};
  let fullText = "";
  let contentList = [];
  const imagesByName = {};
  for (const key of Object.keys(bin)) {
    const meta = bin[key];
    const name = (meta.fileName || "");
    const lower = name.toLowerCase();
    let buf;
    try { buf = await this.helpers.getBinaryDataBuffer(i, key); }
    catch (e) { buf = Buffer.from(meta.data || "", "base64"); }
    if (lower.endsWith("content_list.json")) {
      try { contentList = JSON.parse(buf.toString("utf8")); } catch (e) {}
    } else if (lower.endsWith(".md")) {
      const t = buf.toString("utf8");
      if (t.length > fullText.length) fullText = t;
    } else if (lower.endsWith(".jpg") || lower.endsWith(".jpeg") || lower.endsWith(".png") || lower.endsWith(".gif") || lower.endsWith(".webp")) {
      const ext = lower.split(".").pop();
      const mime = ext === "png" ? "image/png" : (ext === "webp" ? "image/webp" : (ext === "gif" ? "image/gif" : "image/jpeg"));
      const uri = "data:" + mime + ";base64," + buf.toString("base64");
      imagesByName[name] = uri;
      imagesByName[name.split("/").pop()] = uri;
    }
  }
  const figures = []; const tables = []; let fi = 0; let ti = 0;
  for (const el of contentList) {
    if (el.type === "image") {
      fi++;
      const p = el.img_path || el.image_path || "";
      const base = p.split("/").pop();
      const dataUri = imagesByName[p] || imagesByName[base] || "";
      const cap = Array.isArray(el.image_caption) ? el.image_caption.join(" ") : (el.image_caption || el.img_caption || "");
      figures.push({ id: ("fig-" + fi), caption: cap, dataUri: dataUri });
    } else if (el.type === "table") {
      ti++;
      const cap = Array.isArray(el.table_caption) ? el.table_caption.join(" ") : (el.table_caption || "");
      const body = el.table_body || el.table_html || el.text || "";
      const p2 = el.img_path || ""; const base2 = p2.split("/").pop();
      const dataUri = p2 ? (imagesByName[p2] || imagesByName[base2] || "") : "";
      tables.push({ id: ("tbl-" + ti), caption: cap, markdown: body, dataUri: dataUri });
    }
  }
  let fileName = "paper-" + (i + 1) + ".pdf";
  try { fileName = $("Loop Over Papers").first().json.file_name || fileName; } catch (e) {}
  const baseName = fileName.split(".").slice(0, -1).join(".") || fileName;
  out.push({ json: { fileName: fileName, baseName: baseName, fullText: fullText, figures: figures, tables: tables } });
}
return out;

const NL = String.fromCharCode(10);
const items = $input.all();
const out = [];
for (let idx = 0; idx < items.length; idx++) {
  const j = items[idx].json;
  const allFigs = j.figures || [];
  const figs = allFigs.filter(function(f){ return f.dataUri; });
  const tbls = j.tables || [];
  const dsKey = $env.DEEPSEEK_API_KEY;
  const qwKey = $env.DASHSCOPE_API_KEY;
  const ctx = (j.fullText || "").slice(0, 1500);

  const tblBlocks = tbls.map(function(t){ return t.id + " 表标题: " + (t.caption || "(无)") + NL + "表格HTML: " + (t.markdown || "(无)"); }).join(NL + NL);
  const schemaExample = JSON.stringify({ body: { scientificQuestion: "", hypothesis: "", novelty: "", experimentalSetup: "", conclusions: "" }, tables: [{ id: "tbl-1", analysis: "" }] });
  const dsInstruction = ["论文全文(Markdown)：", (j.fullText || "").slice(0, 120000), "", "本论文的表（结合表标题、表格HTML与正文，分析关键数据与结论）：", tblBlocks || "(无表)", "", "请严格只输出如下结构 JSON（不要解释或代码块标记）：", schemaExample, "全部用中文。tables 为每个表 id 各一项，id 与上面一致。"].join(NL);
  const dsBody = { model: "deepseek-v4-pro", messages: [{ role: "system", content: "你是严谨的科学论文审稿人，只输出一个 JSON 对象。" }, { role: "user", content: dsInstruction }], response_format: { type: "json_object" }, temperature: 0.2, max_tokens: 12000 };
  const dsPromise = this.helpers.httpRequest({ method: "POST", url: "https://api.deepseek.com/chat/completions", headers: { Authorization: "Bearer " + dsKey, "Content-Type": "application/json" }, body: dsBody, json: true }).then(function(r){ try { return JSON.parse(r.choices[0].message.content); } catch (e) { return { body: {}, tables: [] }; } }).catch(function(e){ return { body: {}, tables: [], _dsErr: String((e && e.message) || e).slice(0, 120) }; });

  const figPrompt = function(f){ return "这是论文中的一张图。论文背景节选：" + ctx + NL + "图标题：" + (f.caption || "(无标题)") + NL + "请用中文详细解读这张图：展示了什么内容、关键结构或数据、在论文中的科学意义。直接输出分析，不要客套。"; };
  const qwCall = (f) => this.helpers.httpRequest({ method: "POST", url: "https://dashscope.aliyuncs.com/compatible-mode/v1/chat/completions", headers: { Authorization: "Bearer " + qwKey, "Content-Type": "application/json" }, body: { model: "qwen3-vl-plus", messages: [{ role: "user", content: [{ type: "image_url", image_url: { url: f.dataUri } }, { type: "text", text: figPrompt(f) }] }], max_tokens: 1200 }, json: true }).then(function(r){ return { id: f.id, analysis: r.choices[0].message.content }; }).catch(function(e){ return { id: f.id, analysis: "(图分析失败：" + String((e && e.message) || e).slice(0, 100) + ")" }; });

  const figureAnalyses = [];
  for (let i = 0; i < figs.length; i += 5) {
    const part = await Promise.all(figs.slice(i, i + 5).map(qwCall));
    for (let k = 0; k < part.length; k++) figureAnalyses.push(part[k]);
  }
  const dsResult = await dsPromise;
  out.push({ json: { fileName: j.fileName, baseName: j.baseName, body: dsResult.body || {}, tableAnalyses: dsResult.tables || [], figureAnalyses: figureAnalyses, figures: allFigs, tables: tbls } });
}
return out;

const NL = String.fromCharCode(10);
const j = $json;
const fileName = j.fileName; const baseName = j.baseName;
const figs = j.figures || []; const tbls = j.tables || [];
const body = j.body || {};
const figAna = {}; (j.figureAnalyses || []).forEach(function(f){ figAna[f.id] = f.analysis; });
const tblAna = {}; (j.tableAnalyses || []).forEach(function(t){ tblAna[t.id] = t.analysis; });
const L = [];
L.push("# " + fileName); L.push("");
L.push("## 正文分析"); L.push("");
L.push("**科学问题：** " + (body.scientificQuestion || "")); L.push("");
L.push("**科学假设：** " + (body.hypothesis || "")); L.push("");
L.push("**创新点：** " + (body.novelty || "")); L.push("");
L.push("**实验设置：** " + (body.experimentalSetup || "")); L.push("");
L.push("**结论：** " + (body.conclusions || "")); L.push("");
L.push("## 图分析"); L.push("");
figs.forEach(function(f){
  L.push("### " + f.id + (f.caption ? (" — " + f.caption) : ""));
  if (f.dataUri) { L.push('<img src="' + f.dataUri + '" style="max-width:100%" />'); }
  L.push(""); L.push(figAna[f.id] || "(无分析)"); L.push("");
});
L.push("## 表分析"); L.push("");
tbls.forEach(function(t){
  L.push("### " + t.id + (t.caption ? (" — " + t.caption) : ""));
  if (t.dataUri) { L.push('<img src="' + t.dataUri + '" style="max-width:100%" />'); }
  else if (t.markdown) { L.push(""); L.push(t.markdown); }
  L.push(""); L.push(tblAna[t.id] || "(无分析)"); L.push("");
});
return { json: { fileName: fileName, baseName: baseName, paperMarkdown: L.join(NL) } };
